iterate.script:
def svc = r.serviceName as String
if (svc) {
    if (svc.contains('#')) {
        int hashIdx = svc.indexOf('#')
        def partBefore = svc.substring(0, hashIdx)
        def noun = svc.substring(hashIdx + 1)
        def verb = partBefore
        if (verb.contains('.')) {
            verb = verb.substring(verb.lastIndexOf('.') + 1)
        }
        svc = "${verb}#${noun}"
    } else if (svc.contains('.')) {
        svc = svc.substring(svc.lastIndexOf('.') + 1)
    }
}
adkActions.add([
    adkActionLogId: r.adkActionLogId, configId: r.configId,
    agentPartyId: r.agentPartyId, toolName: r.toolName, serviceName: svc,
    argsJson: r.argsJson, verbClass: r.verbClass, decision: r.decision,
    reason: r.reason, resultSummary: r.resultSummary,
    tokensIn: r.tokensIn, tokensOut: r.tokensOut, tokensTotal: r.tokensTotal,
    actionTime: r.actionTime ])

actions.script:
// Cache ownerPartyId → company name to avoid N+1 lookups
def nameCache = [:]
for (def r in rows) {
    def ownerId = r.ownerPartyId as String
    if (ownerId && !nameCache.containsKey(ownerId)) {
        // OwnerCompany: ownerPartyId alias = PTYOWNER.partyId,
        // 'name' alias = COMPANY.organizationName, role must be OrgInternal
        def compList = ec.entity.find('growerp.party.OwnerCompany')
                .condition('ownerPartyId', ownerId)
                .condition('role', 'OrgInternal')
                .selectField('name').list()
        nameCache[ownerId] = compList ? (compList[0].name ?: ownerId) : ownerId
    }

    // Shorten service name to verb#noun (strip package path)
    // e.g. "growerp.100.FinDocServices100.get#FinDoc" → "get#FinDoc"
    //      "growerp.100.SomeServices.myTool"          → "myTool"
    def svc = r.serviceName as String
    if (svc) {
        if (svc.contains('#')) {
            int hashIdx = svc.indexOf('#')
            def partBefore = svc.substring(0, hashIdx)
            def noun = svc.substring(hashIdx + 1)
            def verb = partBefore
            if (verb.contains('.')) {
                verb = verb.substring(verb.lastIndexOf('.') + 1)
            }
            svc = "${verb}#${noun}"
        } else if (svc.contains('.')) {
            svc = svc.substring(svc.lastIndexOf('.') + 1)
        }
    }

    adkActions.add([
        adkActionLogId: r.adkActionLogId, configId: r.configId,
        ownerPartyId: ownerId,
        tenantName: ownerId ? nameCache[ownerId] : null,
        agentPartyId: r.agentPartyId, toolName: r.toolName,
        serviceName: svc,
        argsJson: r.argsJson, verbClass: r.verbClass, decision: r.decision,
        reason: r.reason, resultSummary: r.resultSummary,
        tokensIn: r.tokensIn, tokensOut: r.tokensOut, tokensTotal: r.tokensTotal,
        actionTime: r.actionTime ])
}

